// q4k_gemv.cu — custom in-kernel Q4_K dequant + GEMV for single-token decode.
//
// MODELED EXACTLY on q8_gemv.cu (the proven, correct, ~145-150 GB/s kernel):
// SAME warp-per-rows mapping, SAME shared-x staging, SAME warp-shuffle reduce,
// SAME cubin build/load. The ONLY thing that differs is the per-superblock
// dequant math (Q4_K superblock = 256 weights, vs Q8_0's 32-element block).
//
// WHY: mistral-7b as Q4_K_M reads ~4.0 GB/token vs Q8's 7.55 GB → ~26 tps at
// the proven kernel bandwidth, NO partial residency (the whole decode stays in
// kernel; Q4_K_M's Q6_K tensors take the sibling q6k_gemv kernel).
//
// Q4_K superblock layout (matches dequantize_q4k_row in math.rs EXACTLY):
//   144 bytes per superblock of 256 weights:
//     bytes [0..2)    : f16 super-scale `d`     (little-endian IEEE half)
//     bytes [2..4)    : f16 super-min   `dmin`  (little-endian IEEE half)
//     bytes [4..16)   : 12 bytes of packed 6-bit per-sub-block scales+mins
//                       (8 sub-blocks of 32; decode via get_scale_min_k4)
//     bytes [16..144) : 128 bytes of 4-bit quants (256 nibbles)
//   For sub-block index `js` in 0..8 with (sc, m) = get_scale_min_k4(js):
//     weight = d * sc * q4 - dmin * m         (q4 is the raw 0..15 nibble)
// A weight row of K elements is K/256 contiguous superblocks; the weight matrix
// is row-major [N rows × K], i.e. row r starts at byte offset
//   r * (K/256) * 144.
//
//   out[r] = Σ_k dequant(W[r,k]) * x[k]   for r in [0, N)
//
// The CPU reference (math.rs::dequantize_q4k_row) walks each superblock as four
// passes of 64 outputs (j = 0,64,128,192); for each pass it reads two sub-block
// scale/min pairs (js = j/32 and js+1) and 32 packed quant BYTES (qb = (j/64)*32)
// whose low nibble feeds outputs [j..j+32) and whose high nibble feeds outputs
// [j+32..j+64). We replicate that EXACT element→(sub-block, nibble, qs-byte)
// mapping below so the in-kernel dequant is numerically identical.
//
// get_scale_min_k4(j, scales) — CPU reference (math.rs:52):
//   if j < 4:  ( scales[j]   & 63,                       scales[j+4] & 63 )
//   else:      ( (scales[j+4] & 0xf) | ((scales[j-4] >> 6) << 4),
//                (scales[j+4] >> 4)  | ((scales[j]   >> 6) << 4) )
// Replicated bit-for-bit in `get_scale_min_k4` below (returns the f32 (sc, m)).
//
// VECTORIZED / UNALIGNED-SAFE LOADS (same idioms as q8_gemv.cu):
//   * x via float4 (global) or scalar shared (staged) — IDENTICAL to q8.
//   * The 144-byte superblock stride is not 16/4-aligned in general, so the f16
//     d/dmin, the 12 scale bytes, and the 128 quant bytes are copied into
//     16-byte-aligned locals via `__builtin_memcpy` of COMPILE-TIME-CONSTANT
//     sizes (nvcc lowers to the widest provably-safe load — never a faulting
//     over-aligned wide load), then read back through byte views.
//
// Build: compiled to a native sm_89 CUBIN at build time (build.rs nvcc --cubin
// -arch=sm_89); the cudarc DRIVER loads it (cuModuleLoadData) — no runtime NVRTC.

#include <cuda_fp16.h>

// MUST match Q4K_WARPS_PER_BLOCK / Q4K_ROWS_PER_WARP / Q4K_SHARED_X_MAX_K in
// cuda_matmul.rs (identical values to the q8 path).
#define WARPS_PER_BLOCK 8
#define ROWS_PER_WARP 2
// 16384 floats = 64 KB staged x. Exceeds the 48 KB classic shared cap, so the
// HOST opts the function into the sm_89 large-dynamic-shared limit (≤99 KB on
// the L4) via cuFuncSetAttribute before launch. Raised 8192 -> 16384 so the
// gemma4-12b FFN down-proj (K=15360) stages x ONCE in shared instead of re-
// reading it from global for every output row (the dominant down-matvec cost).
// MUST match Q4K_SHARED_X_MAX_K in cuda_matmul.rs.
#define SHARED_X_MAX_K 16384

// Q4_K constants.
#define QK_K 256          // weights per superblock
#define Q4K_BLK_BYTES 144 // bytes per superblock

// get_scale_min_k4 — replicate math.rs::get_scale_min_k4 (the 6-bit scale/min
// unpack) bit-for-bit. `scales` points at the 12 packed bytes. j in 0..8.
__device__ __forceinline__ void get_scale_min_k4(
    int j, const unsigned char* __restrict__ scales, float& sc, float& m)
{
    if (j < 4) {
        // sc = scales[j] & 63 ; m = scales[j+4] & 63
        sc = (float)(scales[j] & 63);
        m  = (float)(scales[j + 4] & 63);
    } else {
        // sc = (scales[j+4] & 0xf) | ((scales[j-4] >> 6) << 4)
        // m  = (scales[j+4] >> 4)  | ((scales[j]   >> 6) << 4)
        sc = (float)((scales[j + 4] & 0xf) | ((scales[j - 4] >> 6) << 4));
        m  = (float)((scales[j + 4] >> 4)  | ((scales[j]     >> 6) << 4));
    }
}

extern "C" __global__ void q4k_gemv(
    const unsigned char* __restrict__ W, // raw Q4_K bytes, row-major [N × K]
    const float* __restrict__ x,         // activation vector, length K
    float* __restrict__ out,             // output vector, length N
    int N,
    int K)
{
    const int warp_id = threadIdx.x >> 5;        // 0 .. WARPS_PER_BLOCK-1
    const int lane    = threadIdx.x & 31;        // 0 .. 31

    const int sblk_per_row = K / QK_K;           // K / 256 (K is a multiple of 256)
    const size_t row_bytes = (size_t)sblk_per_row * Q4K_BLK_BYTES;

    // (A) Optional shared staging of x — IDENTICAL to q8_gemv.cu.
    extern __shared__ float xsh[];
    const bool use_shared = (K <= SHARED_X_MAX_K);
    if (use_shared) {
        for (int i = threadIdx.x; i < K; i += blockDim.x) {
            xsh[i] = __ldg(x + i);
        }
        __syncthreads();
    }

    // (B) This warp owns ROWS_PER_WARP rows starting at row0.
    const int warp_global = blockIdx.x * WARPS_PER_BLOCK + warp_id;
    const int row0        = warp_global * ROWS_PER_WARP;
    if (row0 >= N) return;

    float partial[ROWS_PER_WARP];
    #pragma unroll
    for (int r = 0; r < ROWS_PER_WARP; ++r) partial[r] = 0.0f;

    // Stride over (superblock × pass) WORK-UNITS so ALL 32 lanes stay busy even
    // when sblk_per_row < 32. A Q4_K superblock is 256 weights = 4 passes of 64;
    // whole-superblock striding left lanes idle for K=4096 (16 superblocks → 16
    // idle lanes). Unit u = sb*4 + pass; total = sblk_per_row*4 (K=4096 → 64 units
    // / 32 lanes = 2 each, full warp). Each unit dequant+dots ONE 64-weight pass.
    // Same math as dequantize_q4k_row; every weight covered once across units, so
    // the warp-shuffle sum over lanes is the full row dot.
    const int total_units = sblk_per_row * 4;
    for (int u = lane; u < total_units; u += 32) {
        const int sb    = u >> 2;                // u / 4  → superblock
        const int pass  = u & 3;                 // u % 4  → 64-weight pass
        const int j     = pass * 64;             // output/x offset within superblock
        const int js    = j >> 5;                // sub-block scale index (j/32)
        const int qb    = pass * 32;             // quant byte offset ((j/64)*32)
        const int xbase = sb * QK_K + j;         // global x base for this pass's 64 values
        const float* __restrict__ xsb =
            use_shared ? (const float*)(xsh + xbase) : (const float*)(x + xbase);
        // gemma4's Q4_K FFN tensors (gate/up) have K=3840 ≤ SHARED_X_MAX_K, so
        // xsb points at SHARED — the per-row re-reads below are cheap shared
        // loads. (No global-x Q4_K FFN case exists here; hoisting x into 64
        // registers would only add pressure and cut occupancy, so we don't.)

        #pragma unroll
        for (int r = 0; r < ROWS_PER_WARP; ++r) {
            const int row = row0 + r;
            if (row >= N) continue;
            const unsigned char* __restrict__ bp =
                W + (size_t)row * row_bytes + (size_t)sb * Q4K_BLK_BYTES;

            // f16 super-scale d (bytes 0..2) + super-min dmin (bytes 2..4),
            // 2-byte-unaligned-safe. (Re-read per pass-unit; 4B header, L2-cached.)
            unsigned short raw_d, raw_dmin;
            __builtin_memcpy(&raw_d,    bp,     sizeof(unsigned short));
            __builtin_memcpy(&raw_dmin, bp + 2, sizeof(unsigned short));
            const float d_val = __half2float(*reinterpret_cast<const __half*>(&raw_d));
            const float dmin  = __half2float(*reinterpret_cast<const __half*>(&raw_dmin));

            // 12 packed scale/min bytes (bytes 4..16).
            unsigned char scales[12];
            __builtin_memcpy(scales, bp + 4, 12);

            // This pass's 32 quant bytes (bytes 16 + qb .. +32) = 64 nibbles.
            unsigned char qbb[32];
            __builtin_memcpy(qbb, bp + 16 + qb, 32);

            // Two sub-block (sc,m) pairs for this pass — EXACTLY dequantize_q4k_row:
            //   out[j   + l] = d*sc1*(qbyte & 0xf) - dmin*m1   (l in 0..32)
            //   out[j+32+l] = d*sc2*(qbyte >> 4)   - dmin*m2
            float sc1, m1, sc2, m2;
            get_scale_min_k4(js,     scales, sc1, m1);
            get_scale_min_k4(js + 1, scales, sc2, m2);
            const float a1 = d_val * sc1, b1 = dmin * m1;   // low nibble gain/offset
            const float a2 = d_val * sc2, b2 = dmin * m2;   // high nibble gain/offset
            float acc = 0.0f;
            #pragma unroll
            for (int l = 0; l < 32; ++l) {
                const unsigned char qbyte = qbb[l];
                acc += (a1 * (float)(qbyte & 0xf) - b1) * xsb[l];
                acc += (a2 * (float)(qbyte >> 4)  - b2) * xsb[32 + l];
            }
            partial[r] += acc;
        }
    }

    // Warp-shuffle reduction across the 32 lanes for each row → lane 0 writes.
    const unsigned FULL = 0xffffffffu;
    #pragma unroll
    for (int r = 0; r < ROWS_PER_WARP; ++r) {
        float p = partial[r];
        #pragma unroll
        for (int offset = 16; offset > 0; offset >>= 1) {
            p += __shfl_down_sync(FULL, p, offset);
        }
        const int row = row0 + r;
        if (lane == 0 && row < N) {
            out[row] = p;
        }
    }
}
